{
  "version": "1.0",
  "name": "水官回潮",
  "player_count_min": 2,
  "player_count_max": 4,
  "duration_minutes": 90,
  "opening_hook": "暴雨倾盆的傍晚，社区茶馆的老周跌跌撞撞冲进来，手里攥着一张湿透的字条，上面潦草写着‘我去找铜镜里的妈妈了’。老周说女儿小雨今早去周氏旧宅取遗物，到现在没回来，电话也打不通。他恳求你们帮忙寻人——但茶馆说书人老吴悄悄拉住你，低声说：‘那栋宅子，二十年前也丢过一个外乡人。’",
  "core_secret": "雨镇每六十年一次的‘水官循环’祭仪：水官（古镇的守护水神）需要一位外乡人自愿献祭，被选中的外乡人通过铜镜与二十年前的失踪者交换灵魂，以此延续水官对古镇的庇护。最近的失踪案正是新一轮祭仪的开端，三日后暴雨之夜将是最后的仪式时刻。",
  "major_conflict": "距离下一个暴雨之夜（即水官仪式窗口）只有不到72小时。守涝人首领老陈表面协助调查，实则暗中准备仪式；失踪者家属老周急切想救人，可能不计后果；文物办干事小刘主张封锁宅子，避免扩散恐慌。三方势力对事件真相了解程度不同，玩家必须在混乱中决定立场——揭露真相并阻止循环、替代祭品、或让仪式完成以换取某种平衡。",
  "required_npcs": [
    {
      "name": "老周",
      "role": "失踪者小雨的父亲，镇上的水电工，性格焦躁但善良，知道一些家族旧事但有意隐瞒。"
    },
    {
      "name": "王老师",
      "role": "民俗学研究生，正在雨镇做田野调查，对水官传说有浓厚兴趣，手中有一份从档案馆复印的民国时期县志残页。"
    },
    {
      "name": "老陈",
      "role": "守涝人首领，铜镜阁的保管者，表面热心助人，实际在维护仪式不受干扰，对水官循环深信不疑。"
    },
    {
      "name": "小刘",
      "role": "文物办干事，负责周氏旧宅的修缮监管，性格刻板，讨厌迷信，认为所有怪事都是人为。"
    },
    {
      "name": "说书人老吴",
      "role": "茶馆常驻说书人，自称‘雨镇活字典’，知道大量传闻但真假参半，关键时刻能给玩家提供隐喻性提示。"
    }
  ],
  "key_locations": [
    {
      "name": "周氏旧宅",
      "description": "一栋两层木结构老宅，建于民国，近期由文物办接管。一楼会客厅、厨房，二楼有三间卧室和一条长走廊。二楼走廊尽头有一面落地铜镜，镜面在暴雨时会泛起水纹。禁忌：雨夜在走廊回望身后会看到另一个自己。"
    },
    {
      "name": "铜镜阁",
      "description": "守涝人的秘密据点，位于水塔检修站地下二层。阁内收藏了七面不同时代的铜镜，中心一面为‘水官镜’，据说是仪式的核心道具。铜镜背面刻有铭文：‘六十年一引，水官归位。’"
    },
    {
      "name": "石板码头",
      "description": "古镇东侧江边的老码头，石阶长满青苔，水位随暴雨上涨。码头下方隐蔽处埋有一块石碑，刻有‘癸亥年水官引’及完整的仪式规则。"
    },
    {
      "name": "龙王庙遗址",
      "description": "位于镇西山坡，只剩地基和几根石柱。中央有一个圆形石台，表面有浅槽导引雨水形成图案。禁忌：移除任何瓦片会触发连续三日的暴雨回溯。"
    },
    {
      "name": "社区茶馆",
      "description": "玩家初始聚集地，也是获取线索和见到关键NPC的枢纽。老吴的茶座旁挂着一面老照片墙，其中一张二十年前的集体照里，一个穿雨衣的陌生人面部被刮花。"
    }
  ],
  "key_clues": [
    {
      "description": "在周氏旧宅二楼小雨卧室的枕头下发现一张泛黄的照片，照片里的年轻女子穿着二十年前的衣物，面容与失踪者小雨几乎一模一样。照片背面用铅笔写着‘1998年6月，水官引’。",
      "points_to_core": "证明小雨不是第一个被选中的外乡人，且外貌与二十年前失踪者一致，指向灵魂交换的循环。"
    },
    {
      "description": "铜镜阁内一本手抄《水官册》，记载了自清光绪年起所有祭品的姓名与日期。最近一条记录是‘乙巳年五月初九，引李氏’，但有人用黑墨覆盖了姓氏，用茶水浸湿后隐约显出一个‘周’字——正是老周的本姓（老周原籍外地，入赘雨镇改姓）。",
      "points_to_core": "直接揭示仪式候选人与老周家族有关，且老周本人可能知情。水官册上的外乡人姓名均非本地人，符合‘必须外乡人’的条件。"
    },
    {
      "description": "石板码头下的石碑碑文完整翻译：‘暴雨连三日，第三夜子时，铜镜向江，外乡人踏水入镜，旧魂归壳，水官得息。违者洪水没镇。’旁边还有一行小字：‘癸亥年水官引记——守涝人立。’",
      "points_to_core": "明确指出了仪式的时间窗口（连下三日暴雨的第三夜）、方法、后果（不按时举行会发洪水），将核心秘密具象化，并暗示守涝人世代守护这一规则。"
    }
  ],
  "endings": [
    {
      "type": "good",
      "description": "玩家集齐所有关键线索，在暴雨第三夜子时之前找到破解方法——用龙王庙遗址的碎瓦划破铜镜表面，使水官循环永久失效。同时救出被困在镜中二十年的两个灵魂（二十年前的失踪者和小雨），她们的身体回归并安全离开。守涝人老陈在真相面前放弃固执，古镇从此再无水官祭。所有NPC存活，但老陈失去力量，铜镜阁废弃。"
    },
    {
      "type": "partial",
      "description": "玩家成功阻止了本次仪式，例如毁掉水官镜或打破子时时限，但小雨未能完全脱离镜中世界——她的身体回来了，精神却停留在二十年前某段记忆里。老陈因仪式失败被水官诅咒，陷入昏迷，需要玩家长期照顾。或者，一名玩家自愿代替小雨成为新的祭品，肉身留在雨镇，灵魂被困在镜子另一侧（该玩家角色永久失去，但换来小雨获救）。另一种选择：玩家让仪式正常进行，小雨与二十年前失踪者的灵魂互换，小雨留在上世纪九十年代，而另一个灵魂回到现代——小雨的家人得到一具陌生人的身体，而老周发誓守住秘密。"
    },
    {
      "type": "bad",
      "description": "玩家未能及时搜集足够线索，或做出了错误判断导致仪式准时完成。暴雨第三夜子时，小雨从周氏旧宅的铜镜中走向石板码头，消失于江面。水官循环继续，但二十年后的今天，铜镜阁里出现了下一个候选者的资料（可能是玩家之一）。老周精神崩溃，老陈沉默地整理仪式记录。所有玩家在最后看到镜子中反射出自己被雨水打湿的面孔——其中一人的脸逐渐变成小雨的模样。或者，由于玩家违反禁忌（如在旧宅走廊回望），全体队员被拉入镜中时空，成为下一轮祭品的候选。"
    }
  ],
  "ai_do_not_change": [
    "水官循环每六十年一次，从未中断，且必须由外乡人自愿踏入铜镜完成。",
    "铜镜（尤其是水官镜）是仪式唯一的关键物品，只有在暴雨中且子时月光照射下才能激活。",
    "回潮现象是时空褶皱，可以短暂连通二十年前，但每次回潮只会持续十五分钟，且只能在同一地点触发。",
    "守涝人由当地家族世袭，知道真相但不干涉结局，他们只确保仪式按古法进行。",
    "所有失踪者均为外地来雨镇短期驻留的人，没有直系亲属常居镇上（老周是例外，因为他当年入赘改了姓，严格说已不算纯正外乡人，但小雨的母亲是外乡人，所以小雨仍被视作‘半个外乡人’，符合条件）。",
    "龙王庙遗址的瓦片一旦被拿走，会立即触发连续暴雨，无法停止。"
  ],
  "ai_freedom_level": "主持人可以自由调整线索获取的顺序、NPC对话细节、次要角色（如茶馆其他常客、文物办同事）的姓名与背景；可以增加或删除非关键的中间线索（如日记片段、天气预报信息）；可以决定回潮现象出现的位置和内容（但不可改变其持续时间和核心机制）；可以调节战斗回避的难度和解决方案。"
}
